1582	  \label{lem:gammaMap_pushforwardCongr_hom}
1583	  \lean{AlgebraicGeometry.gammaMap_pushforwardCongr_hom}
1584	  \uses{lem:gammaPushforwardIso}
1585	  Let \(f, g : X \to \operatorname{Spec} R\) be morphisms of schemes with \(f = g\), and \(M\)
1586	  an \(\mathcal{O}_X\)-module. Applying the global-sections functor \(\Gamma\) to the component
1587	  \((\mathrm{pushforwardCongr}\,(f = g))^{\mathrm{hom}}_M\) of the congruence coherence yields the
1588	  identity morphism on sections:
1589	  \[
1590	    \Gamma\bigl((\mathrm{pushforwardCongr}\,(f = g))^{\mathrm{hom}}_M\bigr)
1591	      = \operatorname{id}.
1592	  \]
1593	\end{lemma}
